```class Solution {
public:
    int minFlipsMonoIncr(string s) {
        int n = s.length();
        int count0 = 0, count1 = 0;
        for (int i = 0; i < n; i++) {
            if (s[i] == '0') {
                count0++;
            } else {
                count1++;
            }
        }
        int flips = count0 - count1;
        if (count0 == 0) {
            return count1;
        } else if (count1 == 0) {
            return count0;
        } else {
            return flips;
        }
    }
};
```

